## 2️⃣ MIDDLEWARE DE TOKENIZAÇÃO DE DADOS SENSÍVEIS

```typescript
// src/security/tokenization-middleware.ts
import crypto from 'crypto';

interface TokenizedValue {
  token: string;
  encryptedOriginal: Buffer;
  iv: Buffer;
  createdAt: number;
  dataType: 'email' | 'phone' | 'cpf' | 'document' | 'address';
}

export class DataTokenizationMiddleware {
  private tokenVault = new Map<string, TokenizedValue>();
  private readonly masterKey: Buffer;
  private readonly ALGORITHM = 'aes-256-cbc';

  constructor(masterKeyHex: string) {
    this.masterKey = Buffer.from(masterKeyHex, 'hex');
  }

  tokenizeSensitiveData(
    plainValue: string,
    dataType: 'email' | 'phone' | 'cpf' | 'document' | 'address'
  ): string {
    const iv = crypto.randomBytes(16);
    const cipher = crypto.createCipheriv(
      this.ALGORITHM,
      this.masterKey,
      iv
    );

    let encrypted = cipher.update(plainValue, 'utf8');
    encrypted = Buffer.concat([encrypted, cipher.final()]);

    const token = `TOKEN_${crypto
      .randomBytes(16)
      .toString('hex')
      .toUpperCase()}`;

    this.tokenVault.set(token, {
      token,
      encryptedOriginal: encrypted,
      iv,
      createdAt: Date.now(),
      dataType,
    });

    return token;
  }

  detokenizeSensitiveData(token: string): string | null {
    const record = this.tokenVault.get(token);

    if (!record) {
      return null;
    }

    try {
      const decipher = crypto.createDecipheriv(
        this.ALGORITHM,
        this.masterKey,
        record.iv
      );

      let decrypted = decipher.update(record.encryptedOriginal);
      decrypted = Buffer.concat([decrypted, decipher.final()]);

      return decrypted.toString('utf8');
    } catch (err) {
      return null;
    }
  }

  // Middleware wrapper for Express/Fastify
  expressMiddleware() {
    return (req: any, res: any, next: any) => {
      const originalBody = { ...req.body };

      // Auto-tokenize sensitive fields
      const sensitivePaths = [
        'email',
        'phone',
        'cpf',
        'document',
        'address',
        'creditCard',
      ];

      sensitivePaths.forEach((path) => {
        if (req.body[path]) {
          const dataType =
            path === 'cpf' ? 'cpf' : path === 'phone' ? 'phone' : 'email';
          req.body[path] = this.tokenizeSensitiveData(
            req.body[path],
            dataType as any
          );
        }
      });

      // Store mapping for audit
      req.tokenMap = new Map(
        sensitivePaths
          .filter((path) => originalBody[path])
          .map((path) => [
            path,
            {
              token: req.body[path],
              original: originalBody[path],
            },
          ])
      );

      next();
    };
  }
}

export const tokenizationMiddleware = new DataTokenizationMiddleware(
  process.env.MASTER_KEY_HEX || ''
);
